import { useEffect, useState } from "react";
import { Alchemy, Network } from "alchemy-sdk";
import "./styles.css";

// Refer to the README doc for more information about using API
// keys in client-side code. You should never do this in production
// level code.
const settings = {
  apiKey: process.env.REACT_APP_ALCHEMY_API_KEY,
  network: Network.ETH_MAINNET,
};

const alchemy = new Alchemy(settings);


export default function NFTPage() {
  const [nftContract, setNftContract] = useState("");
  const [tokenId, setTokenId] = useState("");
  const [nftData, setNftData] = useState(null);
  const [floorPrice, setFloorPrice] = useState(null);

  const fetchNFT = async () => {
    try {
      const data = await alchemy.nft.getNftMetadata(nftContract, tokenId);
      setNftData(data);

      const floor = await alchemy.nft.getFloorPrice(nftContract);
      setFloorPrice(floor.openSea?.floorPrice || floor.looksRare?.floorPrice || "N/A");
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="etherscan-container">
      <h2>NFT Lookup</h2>
      <input
        placeholder="Contract Address"
        value={nftContract}
        onChange={(e) => setNftContract(e.target.value)}
      />
      <input
        placeholder="Token ID"
        value={tokenId}
        onChange={(e) => setTokenId(e.target.value)}
      />
      <button className="button-copy" onClick={fetchNFT}>Fetch NFT</button>

      {nftData && (
        <div className="block-card">
          <div><strong>Name:</strong> {nftData.title}</div>
          <div><strong>Description:</strong> {nftData.description}</div>
          <div><strong>Floor Price:</strong> {floorPrice} ETH</div>
          {nftData.media[0]?.gateway && (
            <img src={nftData.media[0].gateway} alt="NFT" style={{maxWidth:"150px"}}/>
          )}
        </div>
      )}
    </div>
  );
}
